import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, MouseEvent } from 'react';
import { createContext, forwardRef, useContext } from 'react';
import { ChevronLeftIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { Input } from '../input';
import { Separator } from '../separator';
import { Splitter, type SplitterPanelData, useSplitterContext } from '../splitter';
import { Tooltip } from '../tooltip';
import styles from './Sidebar.module.css';

type SidebarSide = 'left' | 'right';
type SidebarConfig = {
  panelId: string;
  side: SidebarSide;
};
type SidebarRootProps = Omit<ComponentProps<typeof Splitter.Root>, 'orientation' | 'panels'> & {
  panelId?: string;
  panels?: ComponentProps<typeof Splitter.Root>['panels'];
  side?: SidebarSide;
};
type SidebarPanelProps = Omit<ComponentProps<typeof Splitter.Panel>, 'id'> & {
  id?: ComponentProps<typeof Splitter.Panel>['id'];
};
type SidebarResizeTriggerProps = Omit<ComponentProps<typeof Splitter.ResizeTrigger>, 'id'> & {
  id?: ComponentProps<typeof Splitter.ResizeTrigger>['id'];
};
type SidebarDefaultSize = ComponentProps<typeof Splitter.Root>['defaultSize'];

const sidebarPanel = {
  id: 'sidebar',
  minSize: '12rem',
  maxSize: '18rem',
  collapsible: true,
  collapsedSize: '3rem',
} satisfies SplitterPanelData;

const contentPanel = { id: 'content' } satisfies SplitterPanelData;

const defaultPanelsBySide = {
  left: [sidebarPanel, contentPanel],
  right: [contentPanel, sidebarPanel],
} satisfies Record<SidebarSide, SplitterPanelData[]>;

const SidebarConfigContext = createContext<SidebarConfig>({
  panelId: 'sidebar',
  side: 'left',
});

function getDefaultSidebarSize(side: SidebarSide): SidebarDefaultSize {
  if (side === 'left') {
    return ['16rem'];
  }

  const defaultSize: SidebarDefaultSize = [];
  defaultSize[1] = '16rem';
  return defaultSize;
}

function getDefaultPanels(side: SidebarSide, panelId: string) {
  const panels = defaultPanelsBySide[side];
  return panels.map((panel) => (panel.id === 'sidebar' ? { ...panel, id: panelId } : panel));
}

function toggleSidebarPanel(splitter: ReturnType<typeof useSplitterContext>, panelId: string) {
  if (splitter.isPanelCollapsed(panelId)) {
    splitter.expandPanel(panelId);
    return;
  }

  splitter.collapsePanel(panelId);
}

const SidebarRoot = forwardRef<ComponentRef<typeof Splitter.Root>, SidebarRootProps>(
  function SidebarRoot(
    { className, panels, defaultSize, panelId = 'sidebar', side = 'left', ...props },
    ref,
  ) {
    return (
      <SidebarConfigContext.Provider value={{ panelId, side }}>
        <Splitter.Root
          {...props}
          ref={ref}
          panels={panels ?? getDefaultPanels(side, panelId)}
          defaultSize={defaultSize ?? getDefaultSidebarSize(side)}
          orientation="horizontal"
          data-side={side}
          data-slot="sidebar-root"
          className={clsx(styles.root, normalizeClassName(className))}
        />
      </SidebarConfigContext.Provider>
    );
  },
);

function useSidebar() {
  const config = useContext(SidebarConfigContext);
  const splitter = useSplitterContext();
  const collapsed = splitter.isPanelCollapsed(config.panelId);

  return {
    collapsed,
    side: config.side,
    state: collapsed ? 'collapsed' : 'expanded',
    toggleSidebar: () => toggleSidebarPanel(splitter, config.panelId),
  };
}

const SidebarPanel = forwardRef<ComponentRef<typeof Splitter.Panel>, SidebarPanelProps>(
  function SidebarPanel({ className, id, ...props }, ref) {
    const config = useContext(SidebarConfigContext);
    const splitter = useSplitterContext();
    const panelId = id ?? config.panelId;
    const collapsed = splitter.isPanelCollapsed(panelId);

    return (
      <Splitter.Panel
        {...props}
        ref={ref}
        id={panelId}
        data-side={config.side}
        data-slot="sidebar-panel"
        data-state={collapsed ? 'collapsed' : 'expanded'}
        className={clsx(styles.panel, normalizeClassName(className))}
      />
    );
  },
);

const SidebarInset = forwardRef<ComponentRef<typeof Splitter.Panel>, SidebarPanelProps>(
  function SidebarInset({ className, id = 'content', ...props }, ref) {
    const { side } = useContext(SidebarConfigContext);

    return (
      <Splitter.Panel
        ref={ref}
        id={id}
        data-side={side}
        data-slot="sidebar-inset"
        className={clsx(styles.inset, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarResizeTrigger = forwardRef<
  ComponentRef<typeof Splitter.ResizeTrigger>,
  SidebarResizeTriggerProps
>(function SidebarResizeTrigger(
  { children, className, id, 'aria-label': ariaLabel = 'Resize sidebar', ...props },
  ref,
) {
  const { panelId, side } = useContext(SidebarConfigContext);
  const resolvedId = id ?? (side === 'left' ? `${panelId}:content` : `content:${panelId}`);

  return (
    <Splitter.ResizeTrigger
      {...props}
      ref={ref}
      id={resolvedId}
      aria-label={ariaLabel}
      data-side={side}
      data-slot="sidebar-resize-trigger"
      className={clsx(styles.resizeTrigger, normalizeClassName(className))}
    >
      {children === undefined ? null : children}
    </Splitter.ResizeTrigger>
  );
});

const SidebarTrigger = forwardRef<HTMLButtonElement, HTMLArkProps<'button'>>(
  function SidebarTrigger(
    {
      className,
      children,
      onClick,
      type = 'button',
      'aria-label': ariaLabel = 'Toggle sidebar',
      ...props
    },
    ref,
  ) {
    const config = useContext(SidebarConfigContext);
    const sidebar = useSplitterContext();
    const collapsed = sidebar.isPanelCollapsed(config.panelId);

    const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
      onClick?.(event);
      if (event.defaultPrevented) return;

      toggleSidebarPanel(sidebar, config.panelId);
    };

    return (
      <ark.button
        ref={ref}
        type={type}
        aria-label={ariaLabel}
        aria-expanded={!collapsed}
        data-scope="sidebar"
        data-part="trigger"
        data-side={config.side}
        data-slot="sidebar-trigger"
        data-state={collapsed ? 'collapsed' : 'expanded'}
        className={clsx(styles.trigger, normalizeClassName(className))}
        onClick={handleClick}
        {...props}
      >
        {children ?? <ChevronLeftIcon />}
      </ark.button>
    );
  },
);

const SidebarLabel = forwardRef<HTMLSpanElement, HTMLArkProps<'span'>>(function SidebarLabel(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="sidebar"
      data-part="label"
      data-slot="sidebar-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarHeader = forwardRef<HTMLElement, HTMLArkProps<'header'>>(function SidebarHeader(
  { className, ...props },
  ref,
) {
  return (
    <ark.header
      ref={ref}
      data-scope="sidebar"
      data-part="header"
      data-slot="sidebar-header"
      className={clsx(styles.header, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarContent = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function SidebarContent(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="sidebar"
      data-part="content"
      data-slot="sidebar-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarFooter = forwardRef<HTMLElement, HTMLArkProps<'footer'>>(function SidebarFooter(
  { className, ...props },
  ref,
) {
  return (
    <ark.footer
      ref={ref}
      data-scope="sidebar"
      data-part="footer"
      data-slot="sidebar-footer"
      className={clsx(styles.footer, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarGroup = forwardRef<HTMLElement, HTMLArkProps<'section'>>(function SidebarGroup(
  { className, ...props },
  ref,
) {
  return (
    <ark.section
      ref={ref}
      data-scope="sidebar"
      data-part="group"
      data-slot="sidebar-group"
      className={clsx(styles.group, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarGroupLabel = forwardRef<HTMLHeadingElement, HTMLArkProps<'h3'>>(
  function SidebarGroupLabel({ className, ...props }, ref) {
    return (
      <ark.h3
        ref={ref}
        data-scope="sidebar"
        data-part="group-label"
        data-slot="sidebar-group-label"
        className={clsx(styles.groupLabel, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarGroupAction = forwardRef<HTMLButtonElement, HTMLArkProps<'button'>>(
  function SidebarGroupAction({ className, type = 'button', ...props }, ref) {
    return (
      <ark.button
        ref={ref}
        type={type}
        data-scope="sidebar"
        data-part="group-action"
        data-slot="sidebar-group-action"
        className={clsx(styles.groupAction, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarGroupContent = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(
  function SidebarGroupContent({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="sidebar"
        data-part="group-content"
        data-slot="sidebar-group-content"
        className={clsx(styles.groupContent, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarMenu = forwardRef<HTMLUListElement, HTMLArkProps<'ul'>>(function SidebarMenu(
  { className, ...props },
  ref,
) {
  return (
    <ark.ul
      ref={ref}
      data-scope="sidebar"
      data-part="menu"
      data-slot="sidebar-menu"
      className={clsx(styles.menu, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarMenuItem = forwardRef<HTMLLIElement, HTMLArkProps<'li'>>(function SidebarMenuItem(
  { className, ...props },
  ref,
) {
  return (
    <ark.li
      ref={ref}
      data-scope="sidebar"
      data-part="menu-item"
      data-slot="sidebar-menu-item"
      className={clsx(styles.menuItem, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarMenuButton = forwardRef<
  HTMLButtonElement,
  HTMLArkProps<'button'> & {
    active?: boolean;
    size?: 'sm' | 'md' | 'lg';
  }
>(function SidebarMenuButton(
  {
    active = false,
    className,
    size = 'md',
    type = 'button',
    'aria-current': ariaCurrent,
    ...props
  },
  ref,
) {
  return (
    <ark.button
      ref={ref}
      type={type}
      aria-current={ariaCurrent ?? (active ? 'page' : undefined)}
      data-scope="sidebar"
      data-part="menu-button"
      data-slot="sidebar-menu-button"
      data-active={active ? '' : undefined}
      data-size={size}
      className={clsx(styles.menuButton, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarMenuAction = forwardRef<HTMLButtonElement, HTMLArkProps<'button'>>(
  function SidebarMenuAction({ className, type = 'button', ...props }, ref) {
    return (
      <ark.button
        ref={ref}
        type={type}
        data-scope="sidebar"
        data-part="menu-action"
        data-slot="sidebar-menu-action"
        className={clsx(styles.menuAction, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarMenuBadge = forwardRef<HTMLDivElement, HTMLArkProps<'div'>>(function SidebarMenuBadge(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="sidebar"
      data-part="menu-badge"
      data-slot="sidebar-menu-badge"
      className={clsx(styles.menuBadge, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarMenuSub = forwardRef<HTMLUListElement, HTMLArkProps<'ul'>>(function SidebarMenuSub(
  { className, ...props },
  ref,
) {
  return (
    <ark.ul
      ref={ref}
      data-scope="sidebar"
      data-part="menu-sub"
      data-slot="sidebar-menu-sub"
      className={clsx(styles.menuSub, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarMenuSubItem = forwardRef<HTMLLIElement, HTMLArkProps<'li'>>(
  function SidebarMenuSubItem({ className, ...props }, ref) {
    return (
      <ark.li
        ref={ref}
        data-scope="sidebar"
        data-part="menu-sub-item"
        data-slot="sidebar-menu-sub-item"
        className={clsx(styles.menuSubItem, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarMenuSubButton = forwardRef<
  HTMLAnchorElement,
  HTMLArkProps<'a'> & {
    active?: boolean;
  }
>(function SidebarMenuSubButton(
  { active = false, className, 'aria-current': ariaCurrent, ...props },
  ref,
) {
  return (
    <ark.a
      ref={ref}
      aria-current={ariaCurrent ?? (active ? 'page' : undefined)}
      data-scope="sidebar"
      data-part="menu-sub-button"
      data-slot="sidebar-menu-sub-button"
      data-active={active ? '' : undefined}
      className={clsx(styles.menuSubButton, normalizeClassName(className))}
      {...props}
    />
  );
});

const SidebarTooltip = function SidebarTooltip({
  children,
  content,
  openDelay = 200,
  closeDelay = 0,
  positioning,
  ...props
}: Omit<ComponentProps<typeof Tooltip>, 'children' | 'disabled' | 'positioning'> & {
  children: ComponentProps<typeof Tooltip.Trigger>['children'];
  content: ComponentProps<typeof Tooltip.Content>['children'];
  positioning?: ComponentProps<typeof Tooltip>['positioning'];
}) {
  const { collapsed, side } = useSidebar();

  return (
    <Tooltip
      {...props}
      openDelay={openDelay}
      closeDelay={closeDelay}
      disabled={!collapsed}
      positioning={{ placement: side === 'left' ? 'right' : 'left', gutter: 8, ...positioning }}
    >
      <Tooltip.Trigger asChild>{children}</Tooltip.Trigger>
      <Tooltip.Positioner>
        <Tooltip.Content>{content}</Tooltip.Content>
      </Tooltip.Positioner>
    </Tooltip>
  );
};

const SidebarInput = forwardRef<ComponentRef<typeof Input.Root>, ComponentProps<typeof Input.Root>>(
  function SidebarInput({ className, ...props }, ref) {
    return (
      <Input.Root
        ref={ref}
        data-slot="sidebar-input"
        className={clsx(styles.input, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const SidebarSeparator = forwardRef<
  ComponentRef<typeof Separator.Root>,
  ComponentProps<typeof Separator.Root>
>(function SidebarSeparator({ className, ...props }, ref) {
  return (
    <Separator.Root
      ref={ref}
      data-slot="sidebar-separator"
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Sidebar = Object.assign(SidebarRoot, {
  Root: SidebarRoot,
  Panel: SidebarPanel,
  Inset: SidebarInset,
  ResizeTrigger: SidebarResizeTrigger,
  Trigger: SidebarTrigger,
  Label: SidebarLabel,
  Input: SidebarInput,
  Header: SidebarHeader,
  Content: SidebarContent,
  Footer: SidebarFooter,
  Separator: SidebarSeparator,
  Group: SidebarGroup,
  GroupLabel: SidebarGroupLabel,
  GroupAction: SidebarGroupAction,
  GroupContent: SidebarGroupContent,
  Menu: SidebarMenu,
  MenuItem: SidebarMenuItem,
  Tooltip: SidebarTooltip,
  MenuButton: SidebarMenuButton,
  MenuAction: SidebarMenuAction,
  MenuBadge: SidebarMenuBadge,
  MenuSub: SidebarMenuSub,
  MenuSubItem: SidebarMenuSubItem,
  MenuSubButton: SidebarMenuSubButton,
});

export { Sidebar, useSidebar };

@layer moduix.components {
  .root {
    --moduix-splitter-width: var(--moduix-sidebar-width, 100%);
    --moduix-splitter-height: var(--moduix-sidebar-height, 100dvh);
    --moduix-splitter-min-height: var(--moduix-sidebar-min-height, 24rem);
    --moduix-splitter-border-color: var(--moduix-sidebar-border-color, var(--moduix-color-border));
    --moduix-splitter-border-width: var(
      --moduix-sidebar-border-width,
      var(--moduix-border-width-sm)
    );
    --moduix-splitter-radius: var(--moduix-sidebar-radius, 0);
    --moduix-splitter-shadow: var(--moduix-sidebar-shadow, none);
    --moduix-splitter-bg: var(--moduix-sidebar-inset-bg, var(--moduix-color-background));
    --moduix-splitter-panel-padding: 0;
    --moduix-splitter-panel-min-height: 0;
    --moduix-splitter-resize-trigger-line-color: var(
      --moduix-sidebar-border-color,
      var(--moduix-color-border)
    );
    --moduix-splitter-resize-trigger-size: var(
      --moduix-sidebar-resize-hit-area,
      var(--moduix-spacing-3)
    );

    isolation: isolate;
  }

  .panel {
    position: relative;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background-color: var(--moduix-sidebar-bg, var(--moduix-color-card));
    color: var(--moduix-sidebar-color, var(--moduix-color-card-foreground));
    transition:
      background-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      color var(--moduix-sidebar-transition, var(--moduix-transition-default));

    &[data-state='collapsed'] {
      .header,
      .footer,
      .group {
        padding-inline: var(--moduix-sidebar-collapsed-padding-x, var(--moduix-spacing-1));
      }

      .header,
      .footer {
        justify-content: center;
      }

      .content {
        overflow-x: hidden;
        overflow-y: auto;
        scrollbar-gutter: auto;
        scrollbar-width: none;
      }

      .label,
      .groupLabel {
        position: absolute;
        width: 1px;
        height: 1px;
        padding: 0;
        margin: -1px;
        overflow: hidden;
        border: 0;
        white-space: nowrap;
        clip-path: inset(50%);
      }

      .menuSub {
        display: none;
      }

      .groupAction,
      .menuAction,
      .menuBadge {
        display: none;
      }

      .menuButton {
        width: var(--moduix-sidebar-collapsed-item-size, var(--moduix-size-md));
        min-height: var(--moduix-sidebar-collapsed-item-size, var(--moduix-size-md));
        margin-inline: auto;
        justify-content: center;
        padding-inline: 0;
        border-color: transparent;
        background-color: transparent;
        box-shadow: none;

        > :not(svg):not([data-sidebar-icon]):not([data-slot='sidebar-label']) {
          display: none;
        }

        > svg,
        > [data-sidebar-icon] {
          margin-inline: auto;
        }

        @media (hover: hover) {
          &:hover {
            background-color: transparent;
          }
        }
      }
    }
  }

  .inset {
    position: relative;
    min-width: 0;
    overflow: auto;
    background-color: var(--moduix-sidebar-inset-bg, var(--moduix-color-background));
    color: var(--moduix-sidebar-inset-color, var(--moduix-color-foreground));
  }

  .resizeTrigger {
    z-index: 2;
  }

  .trigger {
    box-sizing: border-box;
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(--moduix-sidebar-trigger-size, var(--moduix-spacing-7));
    min-width: var(--moduix-sidebar-trigger-size, var(--moduix-spacing-7));
    height: var(--moduix-sidebar-trigger-size, var(--moduix-spacing-7));
    padding: 0;
    border: 0;
    border-radius: var(--moduix-sidebar-trigger-radius, var(--moduix-radius-full));
    background-color: transparent;
    color: var(--moduix-sidebar-muted-color, var(--moduix-color-muted-foreground));
    appearance: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-sidebar-transition, var(--moduix-transition-default));

    > svg {
      width: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
    }

    &:focus-visible {
      outline: var(
          --moduix-sidebar-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-sidebar-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-sidebar-focus-ring-offset, var(--moduix-focus-ring-offset));
    }

    &:disabled,
    &[aria-disabled='true'] {
      opacity: var(--moduix-sidebar-disabled-opacity, var(--moduix-opacity-disabled));
      pointer-events: none;
    }

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
        color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
      }
    }
  }

  .trigger {
    position: relative;
    align-self: flex-start;
    z-index: 4;
    margin-block-start: var(--moduix-sidebar-trigger-offset-y, var(--moduix-spacing-4));
    margin-inline: calc(var(--moduix-sidebar-trigger-size, var(--moduix-spacing-7)) * -0.5);
    border: var(--moduix-sidebar-trigger-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-sidebar-trigger-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-sidebar-trigger-radius, var(--moduix-radius-full));
    background-color: var(--moduix-sidebar-trigger-bg, var(--moduix-color-background));
    box-shadow: var(--moduix-sidebar-trigger-shadow, var(--moduix-shadow-sm));

    &[data-side='left'][data-state='collapsed'] > svg,
    &[data-side='right'][data-state='expanded'] > svg {
      transform: rotate(180deg);
    }

    > svg {
      transition: transform var(--moduix-sidebar-transition, var(--moduix-transition-default));
    }
  }

  .label {
    min-width: 0;
  }

  .header,
  .footer {
    display: flex;
    flex: none;
    align-items: center;
    gap: var(--moduix-sidebar-gap, var(--moduix-spacing-2));
    padding: var(--moduix-sidebar-header-footer-padding, var(--moduix-spacing-3));
  }

  .header {
    border-block-end: var(--moduix-sidebar-section-border-width, 0) solid
      var(--moduix-sidebar-border-color, var(--moduix-color-border));
  }

  .footer {
    border-block-start: var(--moduix-sidebar-section-border-width, 0) solid
      var(--moduix-sidebar-border-color, var(--moduix-color-border));
  }

  .content {
    display: flex;
    flex: 1 1 auto;
    flex-direction: column;
    min-height: 0;
    overflow: auto;
    overscroll-behavior: contain;
    scrollbar-gutter: stable;
  }

  .group {
    display: flex;
    flex-direction: column;
    gap: var(--moduix-sidebar-group-gap, var(--moduix-spacing-1));
    padding: var(--moduix-sidebar-group-padding, var(--moduix-spacing-3));
  }

  .groupLabel {
    min-width: 0;
    margin: 0;
    padding-inline: var(--moduix-sidebar-group-label-padding-x, var(--moduix-spacing-2));
    color: var(--moduix-sidebar-muted-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-sidebar-group-label-font-size, var(--moduix-text-xs));
    font-weight: var(--moduix-sidebar-group-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-sidebar-group-label-line-height, var(--moduix-line-height-text-xs));
    text-transform: var(--moduix-sidebar-group-label-text-transform, none);
  }

  .groupAction {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-sidebar-group-action-size, var(--moduix-size-xs));
    height: var(--moduix-sidebar-group-action-size, var(--moduix-size-xs));
    padding: 0;
    border: 0;
    border-radius: var(--moduix-sidebar-menu-button-radius, var(--moduix-radius-md));
    background-color: transparent;
    color: var(--moduix-sidebar-muted-color, var(--moduix-color-muted-foreground));
    appearance: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      color var(--moduix-sidebar-transition, var(--moduix-transition-default));

    > svg {
      width: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
    }

    &:focus-visible {
      outline: var(
          --moduix-sidebar-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-sidebar-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-sidebar-focus-ring-offset, var(--moduix-focus-ring-offset));
    }

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
        color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
      }
    }
  }

  .group:has(.groupAction) {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    column-gap: var(--moduix-sidebar-gap, var(--moduix-spacing-2));
    row-gap: var(--moduix-sidebar-group-gap, var(--moduix-spacing-1));
  }

  .group:has(.groupAction) .groupLabel {
    grid-column: 1;
  }

  .group:has(.groupAction) .groupAction {
    grid-column: 2;
    align-self: center;
  }

  .groupContent {
    width: 100%;
    min-width: 0;
  }

  .group:has(.groupAction) .groupContent {
    grid-column: 1 / -1;
  }

  .menu,
  .menuSub {
    display: flex;
    flex-direction: column;
    gap: var(--moduix-sidebar-menu-gap, var(--moduix-spacing-1));
    width: 100%;
    min-width: 0;
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .menuItem,
  .menuSubItem {
    position: relative;
    min-width: 0;
  }

  .menuButton,
  .menuSubButton {
    box-sizing: border-box;
    display: flex;
    align-items: center;
    width: 100%;
    min-width: 0;
    border: var(--moduix-sidebar-menu-button-border-width, 0) solid transparent;
    border-radius: var(--moduix-sidebar-menu-button-radius, var(--moduix-radius-md));
    background-color: transparent;
    color: var(--moduix-sidebar-color, var(--moduix-color-card-foreground));
    appearance: none;
    font: inherit;
    text-align: start;
    text-decoration: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      border-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-sidebar-transition, var(--moduix-transition-default));

    > svg {
      flex: none;
      width: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
    }

    > [data-sidebar-icon] {
      flex: none;
    }

    > span:last-child {
      min-width: 0;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    &:focus-visible {
      outline: var(
          --moduix-sidebar-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-sidebar-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-sidebar-focus-ring-offset, var(--moduix-focus-ring-offset));
    }

    &:disabled,
    &[aria-disabled='true'] {
      opacity: var(--moduix-sidebar-disabled-opacity, var(--moduix-opacity-disabled));
      pointer-events: none;
    }

    &[data-active] {
      background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
      color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
      font-weight: var(--moduix-sidebar-active-font-weight, var(--moduix-weight-medium));
    }

    @media (hover: hover) {
      &:hover:not(:disabled, [aria-disabled='true']) {
        background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
        color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
      }
    }
  }

  .menuButton {
    gap: var(--moduix-sidebar-menu-button-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-sidebar-menu-button-height, var(--moduix-size-md));
    padding-block: var(--moduix-sidebar-menu-button-padding-y, var(--moduix-spacing-1));
    padding-inline: var(--moduix-sidebar-menu-button-padding-x, var(--moduix-spacing-2));
    font-size: var(--moduix-sidebar-menu-button-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-sidebar-menu-button-line-height, var(--moduix-line-height-text-sm));

    &[data-size='sm'] {
      min-height: var(--moduix-sidebar-menu-button-height-sm, var(--moduix-size-sm));
      font-size: var(--moduix-sidebar-menu-button-font-size-sm, var(--moduix-text-xs));
    }

    &[data-size='lg'] {
      min-height: var(--moduix-sidebar-menu-button-height-lg, var(--moduix-size-lg));
    }

    > [data-slot='collapsible-indicator'],
    > [data-slot='menu-indicator'] {
      margin-inline-start: auto;
    }
  }

  .panel .menuButton {
    justify-content: flex-start;
  }

  .menuAction {
    position: absolute;
    inset-block-start: calc(
      (var(--moduix-sidebar-menu-button-height, var(--moduix-size-md)) -
          var(--moduix-sidebar-menu-action-size, var(--moduix-size-xs))) /
        2
    );
    inset-inline-end: var(--moduix-sidebar-menu-button-padding-x, var(--moduix-spacing-2));
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-sidebar-menu-action-size, var(--moduix-size-xs));
    height: var(--moduix-sidebar-menu-action-size, var(--moduix-size-xs));
    padding: 0;
    border: 0;
    border-radius: var(--moduix-sidebar-menu-button-radius, var(--moduix-radius-md));
    background-color: transparent;
    color: var(--moduix-sidebar-muted-color, var(--moduix-color-muted-foreground));
    appearance: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-sidebar-transition, var(--moduix-transition-default)),
      color var(--moduix-sidebar-transition, var(--moduix-transition-default));

    > svg {
      width: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-sidebar-icon-size, var(--moduix-spacing-4));
    }

    &:focus-visible {
      outline: var(
          --moduix-sidebar-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-sidebar-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-sidebar-focus-ring-offset, var(--moduix-focus-ring-offset));
    }

    @media (hover: hover) {
      &:hover {
        background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
        color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
      }
    }
  }

  .menuBadge {
    position: absolute;
    inset-block-start: calc(
      (var(--moduix-sidebar-menu-button-height, var(--moduix-size-md)) -
          var(--moduix-sidebar-menu-badge-min-width, 1.5rem)) /
        2
    );
    inset-inline-end: var(--moduix-sidebar-menu-button-padding-x, var(--moduix-spacing-2));
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--moduix-sidebar-menu-badge-min-width, 1.5rem);
    min-height: var(--moduix-sidebar-menu-badge-min-width, 1.5rem);
    padding-inline: var(--moduix-sidebar-menu-badge-padding-x, var(--moduix-spacing-1));
    border-radius: var(--moduix-radius-full);
    background-color: var(--moduix-sidebar-accent-bg, var(--moduix-color-accent));
    color: var(--moduix-sidebar-accent-color, var(--moduix-color-accent-foreground));
    font-size: var(--moduix-text-xs);
    font-variant-numeric: tabular-nums;
    line-height: 1;
  }

  .menuItem:has(.menuAction) .menuButton,
  .menuItem:has(.menuBadge) .menuButton {
    padding-inline-end: calc(
      var(--moduix-sidebar-menu-action-size, var(--moduix-size-xs)) +
        var(--moduix-sidebar-menu-button-padding-x, var(--moduix-spacing-2)) * 2
    );
  }

  .panel[data-state='collapsed'] .menuItem:has(.menuAction) .menuButton,
  .panel[data-state='collapsed'] .menuItem:has(.menuBadge) .menuButton {
    padding-inline-end: 0;
  }

  .menuSub {
    box-sizing: border-box;
    width: auto;
    margin-block-start: var(--moduix-sidebar-menu-sub-margin-y, var(--moduix-spacing-1));
    margin-inline-start: var(--moduix-sidebar-menu-sub-margin-x, var(--moduix-spacing-4));
    padding-inline-start: var(--moduix-sidebar-menu-sub-padding-x, var(--moduix-spacing-2));
    border-inline-start: var(--moduix-sidebar-menu-sub-border-width, var(--moduix-border-width-sm))
      solid var(--moduix-sidebar-border-color, var(--moduix-color-border));
  }

  .menuSubButton {
    gap: var(--moduix-sidebar-menu-sub-button-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-sidebar-menu-sub-button-height, var(--moduix-size-sm));
    padding-inline: var(--moduix-sidebar-menu-sub-button-padding-x, var(--moduix-spacing-2));
    font-size: var(--moduix-sidebar-menu-sub-button-font-size, var(--moduix-text-sm));
    line-height: var(
      --moduix-sidebar-menu-sub-button-line-height,
      var(--moduix-line-height-text-sm)
    );
  }

  .input {
    width: 100%;
  }

  .separator {
    --moduix-separator-color: var(--moduix-sidebar-border-color, var(--moduix-color-border));
  }

  @media (prefers-reduced-motion: reduce) {
    .panel,
    .trigger,
    .groupAction,
    .menuButton,
    .menuAction,
    .menuSubButton {
      transition: none;
    }
  }
}
